mapper.select:
select * from fp_metric_applicability
where tenant_id = #{tenantId}


        and metric_definition_id in
        #{id}


        and 1 = 0


order by created_at asc

select distinct d.*,
       (select count(1) from fp_metric_implementation i where i.tenant_id = d.tenant_id and i.metric_definition_id = d.id) as implementation_count
from fp_metric_definition d
left join fp_metric_applicability a on a.tenant_id = d.tenant_id and a.metric_definition_id = d.id
where d.tenant_id = #{tenantId}
  and d.enabled = #{enabled}
  and (
    (
      a.id is not null
      and a.enabled = true
      and a.scope_type = #{scopeType}
      and (a.object_type is null or a.object_type = '' or a.object_type = #{objectType})
      and (a.relation_type is null or a.relation_type = '' or a.relation_type = #{relationType})
      and (a.source_object_type is null or a.source_object_type = '' or a.source_object_type = #{sourceObjectType})
      and (a.target_object_type is null or a.target_object_type = '' or a.target_object_type = #{targetObjectType})
    )
    or (
      not exists (
        select 1 from fp_metric_applicability fallback
        where fallback.tenant_id = d.tenant_id and fallback.metric_definition_id = d.id
      )
      and d.metric_category = #{scopeType}
      and d.object_type = #{objectType}
    )
  )
order by d.metric_name asc, d.metric_code asc
